using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using YourAppNamespace.Models; // Assuming your Review model is in YourAppNamespace.Models
using YourAppNamespace.Data; // Assuming your DbContext is in YourAppNamespace.Data

namespace YourAppNamespace.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context; // Replace ApplicationDbContext with your actual DbContext

        public ProductController(ApplicationDbContext context)
        {
            _context = context;
        }

        // GET: Product/Details/5
        public IActionResult Details(int id)
        {
            // In a real application, you would fetch the product details here as well
            // For this example, we're focusing on reviews.
            var product = _context.Products.FirstOrDefault(p => p.Id == id); // Assuming you have a Product model and DbSet

            if (product == null)
            {
                return NotFound();
            }

            var reviews = _context.Reviews
                                  .Where(r => r.ProductId == id)
                                  .OrderByDescending(r => r.ReviewDate)
                                  .ToList();

            var viewModel = new ProductDetailsViewModel
            {
                Product = product,
                Reviews = reviews.Select(r => new ReviewViewModel
                {
                    ReviewId = r.Id,
                    UserName = r.UserName,
                    Rating = r.Rating,
                    ReviewTextHtml = FormatReviewText(r.ReviewText),
                    ReviewDate = r.ReviewDate
                }).ToList()
            };

            return View(viewModel);
        }

        private string FormatReviewText(string reviewText)
        {
            if (string.IsNullOrEmpty(reviewText))
            {
                return string.Empty;
            }

            // Basic HTML encoding to prevent XSS for other characters
            string encodedText = System.Net.WebUtility.HtmlEncode(reviewText);

            // Replace **text** with <strong>text</strong>
            encodedText = Regex.Replace(encodedText, @"\*\*(.*?)\*\*", "<strong>$1</strong>");

            // Replace *text* with <em>text</em>
            encodedText = Regex.Replace(encodedText, @"\*(.*?)\*", "<em>$1</em>");

            // Replace newlines with <br /> for display
            encodedText = encodedText.Replace("\n", "<br />");

            return encodedText;
        }
    }

