// --- Razor View (typically in Views/Product/Details.cshtml) ---

@model YourAppNamespace.Models.ProductDetailsViewModel

@{
    ViewData["Title"] = Model.Product.Name;
}

<h1>@Model.Product.Name</h1>
<p>@Model.Product.Description</p>
<p>Price: $@Model.Product.Price</p>

<hr />

<h2>Customer Reviews</h2>

@if (Model.Reviews != null && Model.Reviews.Any())
{
    <div class="reviews-list">
        @foreach (var review in Model.Reviews)
        {
            <div class="review-item mb-4 p-3 border rounded">
                <div class="d-flex justify-content-between align-items-center">
                    <h5 class="mb-0">@review.UserName</h5>
                    <small class="text-muted">@review.ReviewDate.ToShortDateString()</small>
                </div>
                <div class="rating mb-2">
                    @for (int i = 0; i < review.Rating; i++)
                    {
                        <span class="text-warning">&#9733;</span> // Star character
                    }
                    @for (int i = 0; i < (5 - review.Rating); i++)
                    {
                        <span class="text-muted">&#9734;</span> // Empty star character
                    }
                </div>
                <p class="review-text">
                    @Html.Raw(review.ReviewTextHtml)
                </p>
            </div>
        }
    </div>
}
else
{
    <p>No reviews yet. Be the first to review this product!</p>
}

